-- FSI_DEMO_DB.PAYMENTS.MERCHANTS

CREATE OR REPLACE TABLE FSI_DEMO_DB.PAYMENTS.MERCHANTS (

    MERCHANT_ID VARCHAR(20) NOT NULL,
    MERCHANT_NAME VARCHAR(200),
    DBA_NAME VARCHAR(200),
    MCC_CODE VARCHAR(10),
    MCC_DESCRIPTION VARCHAR(100),
    BUSINESS_TYPE VARCHAR(50),
    ADDRESS_LINE1 VARCHAR(200),
    CITY VARCHAR(100),
    STATE VARCHAR(2),
    ZIP_CODE VARCHAR(10),
    COUNTRY VARCHAR(50) DEFAULT 'USA',
    ONBOARDING_DATE DATE,
    STATUS VARCHAR(20),
    RISK_CATEGORY VARCHAR(30),
    RISK_SCORE NUMBER(5,4),
    MONTHLY_VOLUME NUMBER(18,2),
    AVG_TRANSACTION_SIZE NUMBER(12,2),
    CHARGEBACK_RATE NUMBER(6,4),
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (MERCHANT_ID)

);


